mapper.select:
SELECT sum_dy ,plan_id ,team_nm ,NVL(plan_nm,' ' ) plan_nm ,exe_sch_id ,NVL(exe_sch_nm,' ') exe_sch_nm ,tgt_qty ,prg_qty ,err_qty ,to_qty ,DECODE(prg_qty,0,'0%',TO_CHAR((to_qty/prg_qty)*100,'9999')||'%') as tot_rate ,team_cd ,stb_sw_plan_inst_ver FROM st_upd_plan_sts_base_sum WHERE sum_dy between #{fromDate} and #{toDate}
AND team_cd = #{teamCd}
AND stb_sw_plan_inst_ver = #{swVersion}
ORDER BY sum_dy DESC

SELECT TO_CHAR(UUPSH.STM_FIR_REG_DATE,'yyyy.MM.dd') YMD_DATE ,TO_CHAR(UUPSH.STM_FIR_REG_DATE,'HH24:MI') HM_DATE ,(SELECT DISTINCT DQTM.TEAM_NM FROM DM_QLTY_TEAM_MST DQTM WHERE DQTM.TEAM_CD=DDM.TEAM_CD ) AS TEAM_NM ,UUPSH.MODL_NM AS MODL_NM ,DCM.CUG_EXPL AS CUG_EXPL ,UUPM.PLAN_NM AS PLAN_NM ,UUPESL.EXE_SCH_NM AS EXE_SCH_NM ,NVL2(UUPSH.STB_SW_VER ,DECODE(SUBSTR(UUPSH.STB_SW_VER,10,4) ,NULL ,TO_NUMBER(SUBSTR(UUPSH.STB_SW_VER,1,3)) ||'.'||TO_NUMBER(SUBSTR(UUPSH.STB_SW_VER,4,3)) ||'.'||TO_NUMBER(SUBSTR(UUPSH.STB_SW_VER,7,3)) ,TO_NUMBER(SUBSTR(UUPSH.STB_SW_VER,1,3)) ||'.'||TO_NUMBER(SUBSTR(UUPSH.STB_SW_VER,4,3)) ||'.'||TO_NUMBER(SUBSTR(UUPSH.STB_SW_VER,7,3)) ||'-'||SUBSTR(UUPSH.STB_SW_VER,10,4)),' ') AS STB_SW_VER ,NVL2(UUPSH.STB_SW_PLAN_INST_VER ,DECODE(SUBSTR(UUPSH.STB_SW_PLAN_INST_VER,10,4) ,NULL ,TO_NUMBER(SUBSTR(UUPSH.STB_SW_PLAN_INST_VER,1,3)) ||'.'||TO_NUMBER(SUBSTR(UUPSH.STB_SW_PLAN_INST_VER,4,3)) ||'.'||TO_NUMBER(SUBSTR(UUPSH.STB_SW_PLAN_INST_VER,7,3)) ,TO_NUMBER(SUBSTR(UUPSH.STB_SW_PLAN_INST_VER,1,3)) ||'.'||TO_NUMBER(SUBSTR(UUPSH.STB_SW_PLAN_INST_VER,4,3)) ||'.'||TO_NUMBER(SUBSTR(UUPSH.STB_SW_PLAN_INST_VER,7,3)) ||'-'||SUBSTR(UUPSH.STB_SW_PLAN_INST_VER,10,4)),' ') AS STB_SW_PLAN_INST_VER ,DDM.STB_ID AS STB_ID ,UUPSH.ERR_EXPL AS ERR_EXPL ,STB.USER_NUM AS USER_NUM ,STB.USER_SERVICE_NUM AS USER_SERVICE_NUM ,STB.USER_INIT_NUM AS USER_INIT_NUM ,DDPM.CLNT_IPADDR AS CLNT_IPADDR ,(SELECT ACC.CD_NM FROM AD_COMM_CD ACC WHERE COMM_GRP_CD = 'IPTV_STATUS_CODE' AND ACC.COMM_CD = STB.IPTV_STATUS_CODE ) AS IPTV_STATUS_CODE FROM (SELECT * FROM DM_DVC_MST WHERE 1=1 AND TEAM_CD IS NOT NULL ) DDM ,(SELECT * FROM UM_UPD_PLAN_STS_HST WHERE 1=1 AND STB_SW_PLAN_INST_VER IS NOT NULL
AND STM_FIR_REG_DATE BETWEEN TO_DATE(#{from}||'00:00:00','yyyyMMdd HH24:MI:SS') AND TO_DATE(#{to}||'23:59:59','yyyyMMdd HH24:MI:SS')
AND TO_CHAR(STM_FIR_REG_DATE,'YYYYMMDD') IN
#{type}
AND ERR_CD IN ( SELECT ERR_CD FROM UM_ERR_CD_MST UECM WHERE 1=1 AND UECM.STM_CD = '0007' AND UECM.ERR_FG_CD = '4' AND UECM.PRG_STS_FG_CD = '8' ) ) UUPSH ,STB STB ,DM_DVC_PRVN_MST DDPM ,UM_UPD_PLAN_MST UUPM ,UM_UPD_PLAN_EXE_SCH_LST UUPESL ,DM_CUG_MST DCM WHERE 1=1 AND DDM.TEAM_CD IS NOT NULL
AND DDM.TEAM_CD = #{teamCd}
AND DDM.TEAM_CD IN
#{type}
AND UUPSH.STB_ID = DDM.STB_ID(+) AND UUPSH.STB_ID = STB.STB_ID(+) AND UUPSH.STB_ID = DDPM.STB_ID(+) AND UUPSH.PLAN_ID = UUPM.PLAN_ID(+) AND UUPSH.EXE_SCH_ID = UUPESL.EXE_SCH_ID(+)
AND UUPSH.STB_SW_PLAN_INST_VER = #{swVersion}
AND UUPSH.STB_SW_PLAN_INST_VER IN
#{type}
AND UUPSH.PLAN_ID in
#{type}
AND UUPSH.EXE_SCH_ID in
#{type}
AND STB.SERVICE_CODE = DCM.CUG_ID(+) ORDER BY UUPSH.STM_FIR_REG_DATE DESC

SELECT TO_CHAR(UUPSH.STM_FIR_REG_DATE,'yyyy.MM.dd') YMD_DATE ,TO_CHAR(UUPSH.STM_FIR_REG_DATE,'HH24:MI') HM_DATE ,(SELECT DISTINCT DQTM.TEAM_NM FROM DM_QLTY_TEAM_MST DQTM WHERE DQTM.TEAM_CD=DDM.TEAM_CD ) AS TEAM_NM ,UUPSH.MODL_NM AS MODL_NM ,DCM.CUG_EXPL AS CUG_EXPL ,UUPM.PLAN_NM AS PLAN_NM ,UUPESL.EXE_SCH_NM AS EXE_SCH_NM ,NVL2(UUPSH.STB_SW_VER ,DECODE(SUBSTR(UUPSH.STB_SW_VER,10,4) ,NULL ,TO_NUMBER(SUBSTR(UUPSH.STB_SW_VER,1,3)) ||'.'||TO_NUMBER(SUBSTR(UUPSH.STB_SW_VER,4,3)) ||'.'||TO_NUMBER(SUBSTR(UUPSH.STB_SW_VER,7,3)) ,TO_NUMBER(SUBSTR(UUPSH.STB_SW_VER,1,3)) ||'.'||TO_NUMBER(SUBSTR(UUPSH.STB_SW_VER,4,3)) ||'.'||TO_NUMBER(SUBSTR(UUPSH.STB_SW_VER,7,3)) ||'-'||SUBSTR(UUPSH.STB_SW_VER,10,4)),' ') AS STB_SW_VER ,NVL2(UUPSH.STB_SW_PLAN_INST_VER ,DECODE(SUBSTR(UUPSH.STB_SW_PLAN_INST_VER,10,4) ,NULL ,TO_NUMBER(SUBSTR(UUPSH.STB_SW_PLAN_INST_VER,1,3)) ||'.'||TO_NUMBER(SUBSTR(UUPSH.STB_SW_PLAN_INST_VER,4,3)) ||'.'||TO_NUMBER(SUBSTR(UUPSH.STB_SW_PLAN_INST_VER,7,3)) ,TO_NUMBER(SUBSTR(UUPSH.STB_SW_PLAN_INST_VER,1,3)) ||'.'||TO_NUMBER(SUBSTR(UUPSH.STB_SW_PLAN_INST_VER,4,3)) ||'.'||TO_NUMBER(SUBSTR(UUPSH.STB_SW_PLAN_INST_VER,7,3)) ||'-'||SUBSTR(UUPSH.STB_SW_PLAN_INST_VER,10,4)),' ') AS STB_SW_PLAN_INST_VER ,DDM.STB_ID AS STB_ID ,UUPSH.ERR_EXPL AS ERR_EXPL ,STB.USER_NUM AS USER_NUM ,STB.USER_SERVICE_NUM AS USER_SERVICE_NUM ,STB.USER_INIT_NUM AS USER_INIT_NUM ,DDPM.CLNT_IPADDR AS CLNT_IPADDR ,(SELECT ACC.CD_NM FROM AD_COMM_CD ACC WHERE COMM_GRP_CD = 'IPTV_STATUS_CODE' AND ACC.COMM_CD = STB.IPTV_STATUS_CODE ) AS IPTV_STATUS_CODE FROM (SELECT * FROM DM_DVC_MST WHERE 1=1 AND TEAM_CD IS NOT NULL ) DDM ,(SELECT * FROM UM_UPD_PLAN_STS_HST WHERE 1=1 AND STB_SW_PLAN_INST_VER IS NOT NULL
AND STM_FIR_REG_DATE BETWEEN TO_DATE(#{from}||'00:00:00','yyyyMMdd HH24:MI:SS') AND TO_DATE(#{to}||'23:59:59','yyyyMMdd HH24:MI:SS')
AND TO_CHAR(STM_FIR_REG_DATE,'YYYYMMDD') IN
#{type}
AND ERR_CD IN ( SELECT ERR_CD FROM UM_ERR_CD_MST UECM WHERE 1=1 AND UECM.STM_CD = '0007' AND UECM.ERR_FG_CD = '4' AND UECM.PRG_STS_FG_CD = '9' ) ) UUPSH ,STB STB ,DM_DVC_PRVN_MST DDPM ,UM_UPD_PLAN_MST UUPM ,UM_UPD_PLAN_EXE_SCH_LST UUPESL ,DM_CUG_MST DCM WHERE 1=1 AND DDM.TEAM_CD IS NOT NULL
AND DDM.TEAM_CD = #{teamCd}
AND DDM.TEAM_CD IN
#{type}
AND UUPSH.STB_ID = DDM.STB_ID(+) AND UUPSH.STB_ID = STB.STB_ID(+) AND UUPSH.STB_ID = DDPM.STB_ID(+) AND UUPSH.PLAN_ID = UUPM.PLAN_ID(+) AND UUPSH.EXE_SCH_ID = UUPESL.EXE_SCH_ID(+)
AND UUPSH.STB_SW_PLAN_INST_VER = #{swVersion}
AND UUPSH.STB_SW_PLAN_INST_VER IN
#{type}
AND UUPSH.PLAN_ID in
#{type}
AND UUPSH.EXE_SCH_ID in
#{type}
AND STB.SERVICE_CODE = DCM.CUG_ID(+) ORDER BY UUPSH.STM_FIR_REG_DATE DESC
